// Parse action type and extract parameters
const body = $input.item.json.body || $input.item.json;
const message = body.message || '';
const intentData = body.intent || {};
const details = intentData.details || {};

let actionType = 'unknown';
let params = {};

// Calendar operations
if (message.match(/créer.*rendez-vous|ajouter.*calendrier|planifier|rdv/i) || details.action === 'calendar_create') {
  actionType = 'calendar_create';
  params = {
    summary: details.title || 'Rendez-vous',
    description: details.description || message,
    start: details.start_time || new Date(Date.now() + 86400000).toISOString(),
    end: details.end_time || new Date(Date.now() + 90000000).toISOString(),
    attendees: details.attendees || []
  };
}
// Email send
else if (message.match(/envoyer.*email|mail à|écrire à/i) || details.action === 'email_send') {
  actionType = 'email_send';
  params = {
    to: details.recipient || '',
    subject: details.subject || 'Message automatique',
    body: details.body || message
  };
}
// Email summary
else if (message.match(/résumer.*emails|synthèse.*messages|derniers mails/i) || details.action === 'email_summary') {
  actionType = 'email_summary';
  params = {
    maxResults: details.max_results || 20,
    query: details.query || 'is:unread',
    afterDate: details.after_date || new Date(Date.now() - 7 * 86400000).toISOString()
  };
}
// File search
else if (message.match(/chercher.*fichier|trouver.*document|recherche.*drive/i) || details.action === 'file_search') {
  actionType = 'file_search';
  params = {
    query: details.search_query || message.replace(/chercher|trouver|recherche/gi, '').trim()
  };
}
// Unknown action — send to RAG as fallback
else {
  actionType = 'fallback_rag';
  params = { query: message };
}

return { actionType, params, originalMessage: message, channel: body.channel, userId: body.user_id };

// Aggregate action results into a structured response
const actionType = $('Action Parser').item.json.actionType;
const originalMessage = $('Action Parser').item.json.originalMessage;

let result = { success: true, actionType, originalMessage, answer: '', data: {} };

try {
  const input = $input.item.json;
  switch (actionType) {
    case 'calendar_create':
      result.answer = `Rendez-vous créé: ${input.summary || 'Nouveau RDV'} le ${input.start?.dateTime ? new Date(input.start.dateTime).toLocaleString('fr-FR') : 'date à confirmer'}`;
      result.data = { eventId: input.id, link: input.htmlLink };
      break;
    case 'email_send':
      result.answer = `Email envoyé à ${input.to || 'destinataire'} — Sujet: ${input.subject || 'Sans sujet'}`;
      result.data = { messageId: input.id };
      break;
    case 'email_summary':
      result.answer = input.choices?.[0]?.message?.content || 'Résumé non disponible';
      result.data = { emailCount: $items('Gmail Read')?.length || 0 };
      break;
    case 'file_search':
      const files = $input.all();
      if (files.length === 0) { result.answer = 'Aucun fichier trouvé.'; }
      else {
        result.answer = `${files.length} fichier(s) trouvé(s):\n` + files.slice(0, 10).map((f, i) => `${i+1}. ${f.json.name} — ${f.json.webViewLink}`).join('\n');
        result.data = { fileCount: files.length };
      }
      break;
    case 'fallback_rag':
      result.answer = input.answer || input.response || input.result || 'Pas de résultat';
      result.data = { sources: input.sources };
      break;
    default:
      result.success = false;
      result.answer = 'Type d\'action non reconnu.';
  }
} catch (error) {
  result.success = false;
  result.answer = `Erreur: ${typeof error === 'object' ? JSON.stringify(error.message || error) : error}`;
}

return result;
